const now = new Date();
const timeMin = new Date(now.getFullYear(), now.getMonth(), now.getDate()).toISOString();
const tomorrow = new Date(now);
tomorrow.setDate(tomorrow.getDate() + 8);
const timeMax = new Date(tomorrow.getFullYear(), tomorrow.getMonth(), tomorrow.getDate()).toISOString();
return [{ json: { timeMin, timeMax } }];

const events = $input.first().json.items || [];
const userEmail = 'sales.user@example.com';
const alias = 'sales.user@example.com';

function guessCompany(attendees) {
  if (!attendees) return '';
  const externalDomains = attendees
    .map(a => (a.email || '').split('@')[1])
    .filter(d => d && !d.includes('example-company') && !d.includes('Sales UserSales User.com') && !d.includes('gmail.com'));
  if (externalDomains.length === 0) return '';
  const dom = externalDomains[0].split('.')[0];
  return dom.charAt(0).toUpperCase() + dom.slice(1);
}

function guessType(summary, attendees) {
  const s = (summary || '').toLowerCase();
  if (s.includes('1:1') || s.includes('1-1')) return '1:1';
  if (s.includes('standup') || s.includes('weekly') || s.includes('sync')) return 'Internal';
  if (s.includes('intro') || s.includes('discovery') || s.includes('connect')) return 'Discovery';
  if (s.includes('demo')) return 'BD/Sales';
  if (s.includes('interview') || s.includes('candidate')) return 'Recruiting';
  if (!attendees || attendees.length <= 1) return 'Other';
  const allInternal = attendees.every(a => (a.email || '').includes('example-company'));
  return allInternal ? 'Internal' : 'Discovery';
}

function getMeetingLink(event) {
  if (event.hangoutLink) return event.hangoutLink;
  if (event.conferenceData && event.conferenceData.entryPoints) {
    const video = event.conferenceData.entryPoints.find(e => e.entryPointType === 'video');
    if (video) return video.uri;
  }
  const desc = event.description || '';
  const zoomMatch = desc.match(/https:\/\/[a-z0-9-]*\.?zoom\.us\/j\/[0-9]+(\?pwd=[^\s"<>]+)?/);
  if (zoomMatch) return zoomMatch[0];
  const teamsMatch = desc.match(/https:\/\/teams\.microsoft\.com\/[^\s"<>]+/);
  if (teamsMatch) return teamsMatch[0];
  return event.location && event.location.startsWith('http') ? event.location : '';
}

return events
  .filter(e => e.status === 'confirmed')
  .filter(e => e.start && e.start.dateTime)
  .filter(e => {
    const summary = (e.summary || '').toLowerCase();
    return !['ballet', 'leave for', 'lunch', 'block', 'focus time', 'busy', 'home'].some(k => summary.includes(k));
  })
  .filter(e => {
    if (!e.attendees) return false;
    const me = e.attendees.find(a => a.email === userEmail || a.email === alias);
    return me && me.responseStatus !== 'declined';
  })
  .map(e => ({
    json: {
      eventId: e.id,
      summary: e.summary || '(no title)',
      startTime: e.start.dateTime,
      endTime: e.end ? e.end.dateTime : '',
      attendees: (e.attendees || [])
        .filter(a => !a.resource)
        .map(a => a.displayName ? a.displayName + ' (' + a.email + ')' : a.email)
        .join('; '),
      company: guessCompany(e.attendees),
      type: guessType(e.summary, e.attendees),
      meetingLink: getMeetingLink(e)
    }
  }));

const evt = $('Filter + Normalize Events').item.json;

const props = {
  Meeting: { title: [{ text: { content: evt.summary } }] },
  Date: { date: { start: evt.startTime.split('T')[0] } },
  'Start Time': { date: { start: evt.startTime, end: evt.endTime || null } },
  Status: { select: { name: 'Scheduled' } },
  Type: { select: { name: evt.type } },
  'Calendar Event ID': { rich_text: [{ text: { content: evt.eventId } }] }
};

if (evt.attendees) props.Attendees = { rich_text: [{ text: { content: evt.attendees.slice(0, 1900) } }] };
if (evt.company) props.Company = { rich_text: [{ text: { content: evt.company } }] };
if (evt.meetingLink) props['Meeting Link'] = { url: evt.meetingLink };

return [{
  json: {
    body: {
      parent: { database_id: '3879e985-c4dc-4733-9764-3650427f0aca' },
      properties: props
    }
  }
}];
